//! Spec-compliance tests: Style Resolution Deep Audit (ISO 29500-1 §17.7)
//!
//! These tests verify our implementation against specific OOXML style
//! resolution and inheritance constructs.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/styles-audit/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, Mark};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/styles-audit";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_text_node(p: &stemma::ParagraphNode) -> Option<&stemma::TextNode> {
    p.all_inlines().find_map(|inline| match inline {
        InlineNode::Text(t) => Some(t.as_ref()),
        _ => None,
    })
}

fn text_nodes(p: &stemma::ParagraphNode) -> Vec<&stemma::TextNode> {
    p.all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

// ═══════════════════════════════════════════════════════════════════════════
// 1. Default character style (§17.7.4.17)
// ═══════════════════════════════════════════════════════════════════════════

/// ISO 29500-1 §17.7.4.17: Unstyled runs should inherit from the default
/// character style (w:type="character" w:default="1").
///
/// Fixture has a default character style "CustomDefaultChar" with sz=28
/// and color=FF0000. An unstyled run should get these properties.
#[test]
fn spec_default_char_style_font_size() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "default-char-style");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    // Paragraph 1: unstyled run — should get font_size=28 from default char style
    let tn = first_text_node(paras[0]).expect("paragraph 1 should have text");
    assert_eq!(
        tn.style_props.font_size,
        Some(28),
        "unstyled run should inherit font_size=28 from the default character style \
         (CustomDefaultChar with sz=28). Per §17.7.4.17, when a run has no rStyle, \
         the default character style applies."
    );
}

/// ISO 29500-1 §17.7.4.17: Default character style provides base color.
#[test]
fn spec_default_char_style_color() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "default-char-style");
    let paras = common::all_paragraphs(&doc);

    let tn = first_text_node(paras[0]).expect("paragraph 1 should have text");
    assert_eq!(
        tn.style_props.color.as_deref(),
        Some("FF0000"),
        "unstyled run should inherit color=FF0000 from the default character style. \
         Per §17.7.4.17, the default char style is the fallback for runs without rStyle."
    );
}

/// ISO 29500-1 §17.7.4.17 + §17.7.2: Explicit character style overrides
/// default character style for color, but inherits font_size.
#[test]
fn spec_default_char_style_explicit_override() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "default-char-style");
    let paras = common::all_paragraphs(&doc);
    assert!(paras.len() >= 2);

    // Paragraph 2: run with BlueOverride (color=0000FF, no sz)
    let tn = first_text_node(paras[1]).expect("paragraph 2 should have text");
    assert_eq!(
        tn.style_props.color.as_deref(),
        Some("0000FF"),
        "run with BlueOverride char style should get color=0000FF from that style"
    );
    // font_size should come from default char style (28) since BlueOverride doesn't set it
    assert_eq!(
        tn.style_props.font_size,
        Some(28),
        "run with BlueOverride should inherit font_size=28 from default char style \
         (BlueOverride doesn't set sz, so it falls through to default char style)"
    );
}

// ═══════════════════════════════════════════════════════════════════════════
// 2. Deep basedOn chain for numPr (§17.7.4.3 + §17.7.4.14)
// ═══════════════════════════════════════════════════════════════════════════

/// ISO 29500-1 §17.7.4.3 + §17.7.4.14: numPr defined on root style
/// (NumStyleA) should be inherited through 3-level basedOn chain.
///
/// NumStyleA → numPr(numId=1, ilvl=0)
/// NumStyleB → basedOn NumStyleA (adds indent)
/// NumStyleC → basedOn NumStyleB (adds bold)
///
/// Paragraph using NumStyleC should have numbering from NumStyleA.
#[test]
fn spec_deep_numpr_chain_style_c() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "deep-numpr-chain");
    let paras = common::all_paragraphs(&doc);

    let p_c = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("via StyleC"))
        .expect("should find paragraph with StyleC");

    assert!(
        p_c.numbering.is_some(),
        "paragraph using NumStyleC should inherit numbering from NumStyleA \
         through the 3-level basedOn chain (C → B → A). Per §17.7.4.14, \
         numPr from the resolved style provides numbering."
    );
}

/// ISO 29500-1 §17.7.4.14: Paragraph using root style (NumStyleA) directly
/// should have numbering.
#[test]
fn spec_deep_numpr_chain_style_a() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "deep-numpr-chain");
    let paras = common::all_paragraphs(&doc);

    let p_a = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("via StyleA"))
        .expect("should find paragraph with StyleA");

    assert!(
        p_a.numbering.is_some(),
        "paragraph using NumStyleA directly should have numbering from its own numPr"
    );
}

/// ISO 29500-1 §17.7.4.3 + §17.7.4.14: Paragraph using middle style
/// (NumStyleB, basedOn A) should inherit numbering from A.
#[test]
fn spec_deep_numpr_chain_style_b() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "deep-numpr-chain");
    let paras = common::all_paragraphs(&doc);

    let p_b = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("via StyleB"))
        .expect("should find paragraph with StyleB");

    assert!(
        p_b.numbering.is_some(),
        "paragraph using NumStyleB should inherit numbering from NumStyleA \
         through the basedOn chain (B → A). Per §17.7.4.14 + §17.7.4.3."
    );
}

// ═══════════════════════════════════════════════════════════════════════════
// 3. wholeTable conditional — discarded per MS-OI29500 §17.18.89
// ═══════════════════════════════════════════════════════════════════════════

/// MS-OI29500 §2.1.557 (§17.18.89): Word discards properties from tblStylePr
/// with type="wholeTable". Cells should NOT get shading from wholeTable.
///
/// The fixture's style has shading AABBCC only in the wholeTable tblStylePr
/// (no root-level tcPr), so cells have no shading.
#[test]
fn spec_whole_table_conditional_shading() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "whole-table-conditional");
    let table = first_table(&doc);

    // No cell should have shading — wholeTable conditional is discarded
    for (row_idx, row) in table.rows.iter().enumerate() {
        for (col_idx, cell) in row.cells.iter().enumerate() {
            assert!(
                cell.formatting.shading.is_none(),
                "cell ({row_idx},{col_idx}) should NOT have shading — wholeTable conditional is \
                 discarded per MS-OI29500 §17.18.89"
            );
        }
    }
}

/// MS-OI29500 §2.1.557 (§17.18.89): Word discards properties from tblStylePr
/// with type="wholeTable". Runs should NOT be bold from wholeTable.
///
/// The fixture's style has bold only in the wholeTable tblStylePr rPr
/// (no root-level rPr), so runs are not bold.
#[test]
fn spec_whole_table_conditional_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "whole-table-conditional");
    let table = first_table(&doc);

    for (row_idx, row) in table.rows.iter().enumerate() {
        for (col_idx, cell) in row.cells.iter().enumerate() {
            for block in &cell.blocks {
                if let BlockNode::Paragraph(p) = block {
                    for tn in text_nodes(p) {
                        if tn.text.trim().is_empty() {
                            continue;
                        }
                        assert!(
                            !tn.marks.contains(&Mark::Bold),
                            "text '{}' in cell ({},{}) should NOT be bold — wholeTable \
                             conditional is discarded per MS-OI29500 §17.18.89",
                            tn.text,
                            row_idx,
                            col_idx
                        );
                    }
                }
            }
        }
    }
}

// ═══════════════════════════════════════════════════════════════════════════
// 4. Conditional precedence: firstRow vs firstCol (§17.7.6)
// ═══════════════════════════════════════════════════════════════════════════

/// MS-OI29500 §17.7.6(c): firstRow has higher precedence than firstCol.
/// Cell (0,0) is at the intersection — firstRow shading (FF0000) should win.
///
/// Conditional precedence may be incorrect.
#[test]
fn spec_conditional_precedence_first_row_wins() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    // Cell (0,0): intersection of firstRow and firstCol.
    // Per MS-OI29500 §17.7.6(c), firstRow has higher precedence than firstCol.
    let cell_0_0 = &table.rows[0].cells[0];
    let shading = cell_0_0
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have shading from conditional formatting");
    assert_eq!(
        shading.fill.as_deref(),
        Some("FF0000"),
        "cell (0,0) shading should be FF0000 (red) from firstRow conditional, \
         not 0000FF (blue) from firstCol. Per MS-OI29500 §17.7.6(c), firstRow \
         has higher precedence than firstCol."
    );
}

/// MS-OI29500 §17.7.6(c): Cell (0,1) is firstRow only — should be red.
#[test]
fn spec_conditional_precedence_first_row_only() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    let cell_0_1 = &table.rows[0].cells[1];
    let shading = cell_0_1
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,1) should have shading from firstRow conditional");
    assert_eq!(
        shading.fill.as_deref(),
        Some("FF0000"),
        "cell (0,1) shading should be FF0000 (red) from firstRow conditional"
    );
}

/// MS-OI29500 §17.7.6(c): Cell (1,0) is firstCol only — should be blue.
#[test]
fn spec_conditional_precedence_first_col_only() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    let cell_1_0 = &table.rows[1].cells[0];
    let shading = cell_1_0
        .formatting
        .shading
        .as_ref()
        .expect("cell (1,0) should have shading from firstCol conditional");
    assert_eq!(
        shading.fill.as_deref(),
        Some("0000FF"),
        "cell (1,0) shading should be 0000FF (blue) from firstCol conditional"
    );
}

/// MS-OI29500 §17.7.6(c): Cell (1,1) is neither firstRow nor firstCol — no shading.
#[test]
fn spec_conditional_precedence_no_conditional() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    let cell_1_1 = &table.rows[1].cells[1];
    // No conditional applies, so shading should be None or not from conditionals
    if let Some(shading) = &cell_1_1.formatting.shading {
        assert!(
            shading.fill.as_deref() != Some("FF0000") && shading.fill.as_deref() != Some("0000FF"),
            "cell (1,1) should NOT have firstRow or firstCol shading, \
             but got fill={:?}",
            shading.fill
        );
    }
    // None is also acceptable — no conditional matched
}

// ═══════════════════════════════════════════════════════════════════════════
// 5. Toggle property XOR through basedOn chain (§17.7.3)
// ═══════════════════════════════════════════════════════════════════════════

/// ISO 29500-1 §17.7.3: Single-level bold=on → effective bold=on.
#[test]
fn spec_toggle_xor_based_on_root_bold() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-based-on");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Root bold on"))
        .expect("should find ToggleRoot paragraph");

    let tn = first_text_node(p1).expect("paragraph should have text");
    assert!(
        tn.marks.contains(&Mark::Bold),
        "ToggleRoot (bold=on) should produce bold text. \
         Single-level bold does not involve XOR."
    );
}

/// ISO 29500-1 §17.7.3 + §17.7.4.3: Two levels both bold=on in basedOn
/// chain. Per §17.7.3, toggle properties XOR across hierarchy levels.
///
/// ToggleRoot: bold=on
/// ToggleChild (basedOn Root): bold=on
///
/// Within the basedOn chain for the para style, the resolved value is
/// on XOR on = off. The effective paragraph-level bold contribution is off.
///
/// NOTE: §17.7.3 says XOR applies across "hierarchy levels" which means
/// across the document defaults / table / numbering / paragraph / character
/// / direct levels — NOT within a single basedOn chain. Within a basedOn
/// chain, overlay semantics apply (child overrides parent). So the
/// ToggleChild style's bold=on simply OVERRIDES ToggleRoot's bold=on,
/// and the paragraph-level contribution is bold=on, not XOR.
///
/// The XOR behavior applies when combining e.g. para style bold with
/// char style bold (different hierarchy levels per §17.7.2).
#[test]
fn spec_toggle_xor_based_on_both_on() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-based-on");
    let paras = common::all_paragraphs(&doc);

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Child XOR off"))
        .expect("should find ToggleChild paragraph");

    let tn = first_text_node(p2).expect("paragraph should have text");
    // Per §17.7.3 and §17.7.4.3: within a basedOn chain, child overrides
    // parent. ToggleChild sets bold=on, overriding ToggleRoot's bold=on.
    // The resolved paragraph style bold is ON.
    // XOR only applies across hierarchy levels (para vs char vs direct),
    // not within a single basedOn chain.
    assert!(
        tn.marks.contains(&Mark::Bold),
        "ToggleChild (bold=on, basedOn ToggleRoot bold=on): within a basedOn chain, \
         the child's bold=on overrides the parent's bold=on (no XOR within a single \
         chain level). The effective paragraph style contribution is bold=on."
    );
}

/// ISO 29500-1 §17.7.3 + §17.7.4.3: Root bold=on, child bold=off.
/// Within the basedOn chain, child's explicit off overrides root's on.
/// Resolved paragraph-level contribution: bold=off.
#[test]
fn spec_toggle_xor_based_on_off_child() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-based-on");
    let paras = common::all_paragraphs(&doc);

    let p3 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Off child XOR on"))
        .expect("should find ToggleOffChild paragraph");

    let tn = first_text_node(p3).expect("paragraph should have text");
    // ToggleOffChild sets bold=off (val="0"), overriding ToggleRoot's bold=on.
    // Within a basedOn chain, child's explicit value wins.
    assert!(
        !tn.marks.contains(&Mark::Bold),
        "ToggleOffChild (bold=off, basedOn ToggleRoot bold=on): within a basedOn chain, \
         the child's explicit bold=off overrides the parent's bold=on. \
         The effective paragraph-level contribution is bold=off."
    );
}
